import { useEffect, useRef, useState } from 'react';
import { createChart, BaselineSeries } from 'lightweight-charts';

function BaselineChartBTC({sparklinedata}) {
  let [newarrbtc, changenewarr] = useState(sparklinedata)
  const chartContainerRef = useRef(null);
  useEffect(() => {
    const chart = createChart(chartContainerRef.current, {
  width: 200,
  height: 80,

  layout: {
    textColor: '#cbd5e1',
    background: {
      type: 'solid',
      color: '#0b0f19',
    },
  },

  grid: {
    vertLines: { visible: false },
    horzLines: { visible: false },
  },

  rightPriceScale: {
    borderVisible: false,
    visible: false,
  },

  timeScale: {
    borderVisible: false,
    visible: false,
    rightOffset: 6,
    barSpacing: 8,
    minBarSpacing: 2,
    fixLeftEdge: true,
    fixRightEdge: true,
  },

  crosshair: {
    vertLine: {
      visible: false,
      labelVisible: false,
    },
    horzLine: {
      visible: false,
      labelVisible: false,
    },
  },


  handleScroll: {
    mouseWheel: false,
    pressedMouseMove: false,
    horzTouchDrag: false,
    vertTouchDrag: false,
  },

  handleScale: {
    mouseWheel: false,
    pinch: false,
    axisPressedMouseMove: {
      time: false,
      price: false,
    },
  },

  localization: {
    locale: 'en-GB',
  },
});

 
    let res = newarrbtc.map(([time, value], index) => ({
      index: index, value: Number(value), time: time / 1000
    }))
    baselineSeries.setData(
      res
    );
   

    chart.timeScale().fitContent();

    return () => chart.remove();
  }, []);
 useEffect(() => {
      console.log(newarrbtc)
    }, [newarrbtc])
  return <div ref={chartContainerRef} />;
}
export default BaselineChartBTC
